import{_ as a}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as n}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as i,o as t,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Cloudflare API-token","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/Safety/cloudflare-api-token.md","filePath":"nl-NL/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),d={name:"nl-NL/Safety/cloudflare-api-token.md"};function r(s,e,c,p,g,h){return t(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API-token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API-token&quot;">​</a></h1><p>Cloudflare API-gegevens laten ImgBed de Cloudflare CDN-cache opschonen nadat bestanden zijn gewijzigd.</p><p><img src="'+a+'" alt="Cloudflare API-token instellingen" loading="lazy"></p><h2 id="waar-je-dit-configureert" tabindex="-1">Waar je dit configureert <a class="header-anchor" href="#waar-je-dit-configureert" aria-label="Permalink to &quot;Waar je dit configureert&quot;">​</a></h2><p>Open het beheer en ga naar:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>Je moet invullen:</p><ul><li>Zone ID</li><li>Account-e-mail</li><li>API Key</li></ul><h2 id="wat-deze-instelling-doet" tabindex="-1">Wat deze instelling doet <a class="header-anchor" href="#wat-deze-instelling-doet" aria-label="Permalink to &quot;Wat deze instelling doet&quot;">​</a></h2><p>Cloudflare kan openbare afbeeldings-URL&#39;s cachen.</p><p>Caching maakt levering sneller, maar kan er ook voor zorgen dat oude inhoud nog even zichtbaar blijft nadat je een bestand verwijdert, blokkeert, vervangt of verplaatst.</p><p>Nadat Cloudflare API-gegevens zijn ingesteld, probeert ImgBed de bijbehorende Cloudflare-cache te wissen zodra zulke acties klaar zijn.</p><p>Dit is nuttig wanneer:</p><ul><li>je een afbeelding verwijdert en wilt dat de openbare link zo snel mogelijk stopt met werken.</li><li>je een afbeelding blokkeert en wilt dat bezoekers het oorspronkelijke bestand niet meer zien.</li><li>je een bestand met dezelfde naam vervangt en wilt dat bezoekers sneller de nieuwe versie zien.</li><li>je bestanden verplaatst of hernoemt en oude padcache snel wilt verversen.</li><li>je openbare toegangsregels wijzigt en de openbare gallery of random image-cache sneller wilt bijwerken.</li></ul><h2 id="als-je-dit-leeg-laat" tabindex="-1">Als je dit leeg laat <a class="header-anchor" href="#als-je-dit-leeg-laat" aria-label="Permalink to &quot;Als je dit leeg laat&quot;">​</a></h2><p>ImgBed werkt ook zonder deze instelling normaal.</p><p>Het enige verschil is dat ImgBed de Cloudflare CDN-cache niet actief wist. Bezoekers kunnen oude inhoud blijven zien totdat de Cloudflare-cache vanzelf verloopt.</p><h2 id="zone-id-vinden" tabindex="-1">Zone ID vinden <a class="header-anchor" href="#zone-id-vinden" aria-label="Permalink to &quot;Zone ID vinden&quot;">​</a></h2><p>De Zone ID is de Cloudflare Zone ID van de site die je ImgBed-domein gebruikt.</p><ol><li>Log in op het Cloudflare Dashboard.</li><li>Open de site waarin je ImgBed-domein zit.</li><li>Zoek <code>Zone ID</code> op de overzichtspagina van de site.</li><li>Kopieer deze naar het veld <code>Zone ID</code> in ImgBed.</li></ol><p>Dit is de Zone ID van de site, niet de account-ID.</p><h2 id="account-e-mail" tabindex="-1">Account-e-mail <a class="header-anchor" href="#account-e-mail" aria-label="Permalink to &quot;Account-e-mail&quot;">​</a></h2><p>Vul het e-mailadres in waarmee je inlogt bij Cloudflare.</p><p>Dit moet passen bij de API Key die je hieronder invult.</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>Vul je Cloudflare Global API Key in.</p><ol><li>Log in op het Cloudflare Dashboard.</li><li>Open je profiel.</li><li>Ga naar de API Tokens-pagina.</li><li>Zoek <code>Global API Key</code>.</li><li>Bekijk en kopieer deze.</li><li>Plak deze in het veld <code>API Key</code> in ImgBed.</li></ol><p><img src="'+n+'" alt="Global API Key bekijken" loading="lazy"></p><h2 id="wanneer-dit-effect-heeft" tabindex="-1">Wanneer dit effect heeft <a class="header-anchor" href="#wanneer-dit-effect-heeft" aria-label="Permalink to &quot;Wanneer dit effect heeft&quot;">​</a></h2><p>Vul de velden in en sla de instellingen op.</p><p>Toekomstige bestandswijzigingen proberen daarna automatisch Cloudflare-cache te wissen. Eerdere acties worden niet met terugwerkende kracht opgeschoond. Heb je vóór deze instelling een bestand verwijderd of vervangen, wacht dan tot Cloudflare-cache verloopt of wis die handmatig in Cloudflare.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="is-dit-verplicht" tabindex="-1">Is dit verplicht? <a class="header-anchor" href="#is-dit-verplicht" aria-label="Permalink to &quot;Is dit verplicht?&quot;">​</a></h3><p>Nee.</p><p>Gebruik je domein geen Cloudflare, of vind je CDN-cachevertraging geen probleem, dan kun je dit leeg laten.</p><h3 id="breken-verkeerde-gegevens-uploads" tabindex="-1">Breken verkeerde gegevens uploads? <a class="header-anchor" href="#breken-verkeerde-gegevens-uploads" aria-label="Permalink to &quot;Breken verkeerde gegevens uploads?&quot;">​</a></h3><p>Meestal niet.</p><p>Verkeerde gegevens voorkomen alleen dat ImgBed Cloudflare-cache wist. Uploaden en normale bestandstoegang blijven normaal werken.</p><h3 id="waarom-kan-een-verwijderde-afbeelding-nog-steeds-worden-geopend" tabindex="-1">Waarom kan een verwijderde afbeelding nog steeds worden geopend? <a class="header-anchor" href="#waarom-kan-een-verwijderde-afbeelding-nog-steeds-worden-geopend" aria-label="Permalink to &quot;Waarom kan een verwijderde afbeelding nog steeds worden geopend?&quot;">​</a></h3><p>De meest voorkomende reden is dat Cloudflare het oude bestand nog in cache heeft.</p><p>Met correcte Cloudflare API-gegevens wist ImgBed de cache van de betreffende URL wanneer een bestand wordt verwijderd.</p><h3 id="waarom-zie-ik-nog-de-oude-afbeelding-na-vervangen" tabindex="-1">Waarom zie ik nog de oude afbeelding na vervangen? <a class="header-anchor" href="#waarom-zie-ik-nog-de-oude-afbeelding-na-vervangen" aria-label="Permalink to &quot;Waarom zie ik nog de oude afbeelding na vervangen?&quot;">​</a></h3><p>Ook dit komt meestal door CDN-cache.</p><p>Zodra deze instelling is geconfigureerd, probeert ImgBed de cache van de oude URL te wissen wanneer een bestand met dezelfde naam wordt overschreven.</p>',44)])])}const b=i(d,[["render",r]]);export{m as __pageData,b as default};
